package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.GsonBuilder;
import java.lang.reflect.Field;

public class GsonBuilderTest {

  @Test
  public void testEnableComplexMapKeySerialization() throws Exception {
    GsonBuilder builder = new GsonBuilder();
    // Initially complexMapKeySerialization should be false (default)
    Field field = GsonBuilder.class.getDeclaredField("complexMapKeySerialization");
    field.setAccessible(true);
    boolean beforeValue = (boolean) field.get(builder);
    assertFalse(beforeValue, "complexMapKeySerialization should be false before enabling");

    // Call enableComplexMapKeySerialization
    GsonBuilder returned = builder.enableComplexMapKeySerialization();

    // The method should return the same instance for chaining
    assertSame(builder, returned);

    // After calling, complexMapKeySerialization should be true
    boolean afterValue = (boolean) field.get(builder);
    assertTrue(afterValue, "complexMapKeySerialization should be true after enabling");
  }
}
